def find_minimum_range(arrays):
    merged = []
    for array in arrays:
        merged.extend(array)
    merged.sort()
    n = len(merged)
    total_arrays = len(arrays)
    left = 0
    count = 0
    min_range = float('inf')
    for right in range(n):
        current_val = merged[right]
        current_array = current_val[1]
        if count == 0:
            count += 1
        elif current_array != merged[left][1]:
            count += 1
        if count == total_arrays:
            current_range = merged[right][0] - merged[left][0]
            if current_range < min_range:
                min_range = current_range
            while left < right and count == total_arrays:
                left += 1
                if merged[left][1] != merged[left-1][1]:
                    count -= 1
    return (merged[left][0], merged[right][0]) if min_range != float('inf') else None

